fragment:











    @($"https://{(string)context.Variables["storageAccount"]}.blob.core.windows.net/?restype=service&comp=userdelegationkey")
    POST

        2020-12-06

    @{
        var start = DateTime.UtcNow.ToString("yyyy-MM-ddTHH:mm:ssZ");
        var expiry = DateTime.UtcNow.AddMinutes(10).ToString("yyyy-MM-ddTHH:mm:ssZ");
        return $"{start}{expiry}";
    }




<set-variable name="sasToken" value="@{
    try
    {
        var response = ((IResponse)context.Variables["delegationKeyResponse"]);
        if (response.StatusCode != 200)
        {
            context.Trace("User delegation key request failed with status: " + response.StatusCode);
            return "";
        }

        var body = response.Body.As();
        var xml = System.Xml.Linq.XDocument.Parse(body);
        var root = xml.Root;

        var signedOid = root.Element("SignedOid")?.Value ?? "";
        var signedTid = root.Element("SignedTid")?.Value ?? "";
        var signedKeyStart = root.Element("SignedStart")?.Value ?? "";
        var signedKeyExpiry = root.Element("SignedExpiry")?.Value ?? "";
        var signedKeyService = root.Element("SignedService")?.Value ?? "";
        var signedKeyVersion = root.Element("SignedVersion")?.Value ?? "";
        var keyValue = root.Element("Value")?.Value ?? "";

        var permissions = (string)context.Variables["permissions"];
        var expiry = (string)context.Variables["sasExpiry"];
        var canonicalizedResource = (string)context.Variables["canonicalizedResource"];
        var signedProtocol = (string)context.Variables["signedProtocol"];
        var signedVersion = (string)context.Variables["signedVersion"];
        var signedResource = (string)context.Variables["signedResource"];

        // User Delegation SAS string-to-sign (v2020-12-06)
        var stringToSign =
            permissions + "\n" +
            "" + "\n" +                 // signedStart (empty = now)
            expiry + "\n" +
            canonicalizedResource + "\n" +
            signedOid + "\n" +
            signedTid + "\n" +
            signedKeyStart + "\n" +
            signedKeyExpiry + "\n" +
            signedKeyService + "\n" +
            signedKeyVersion + "\n" +
            "" + "\n" +                 // signedAuthorizedUserObjectId
            "" + "\n" +                 // signedUnauthorizedUserObjectId
            "" + "\n" +                 // signedCorrelationId
            "" + "\n" +                 // signedIP
            signedProtocol + "\n" +
            signedVersion + "\n" +
            signedResource + "\n" +
            "" + "\n" +                 // signedSnapshotTime
            "" + "\n" +                 // signedEncryptionScope
            "" + "\n" +                 // rscc
            "" + "\n" +                 // rscd
            "" + "\n" +                 // rsce
            "" + "\n" +                 // rscl
            "";                         // rsct

        // Sign with the user delegation key using HMAC-SHA256
        var key = Convert.FromBase64String(keyValue);
        string signature;
        using (var hmac = new System.Security.Cryptography.HMACSHA256(key))
        {
            var hash = hmac.ComputeHash(System.Text.Encoding.UTF8.GetBytes(stringToSign));
            signature = Convert.ToBase64String(hash);
        }

        // Build User Delegation SAS token
        return $"sp={permissions}" +
            $"&se={expiry}" +
            $"&spr={signedProtocol}" +
            $"&sv={signedVersion}" +
            $"&sr={signedResource}" +
            $"&skoid={signedOid}" +
            $"&sktid={signedTid}" +
            $"&skt={signedKeyStart}" +
            $"&ske={signedKeyExpiry}" +
            $"&sks={signedKeyService}" +
            $"&skv={signedKeyVersion}" +
            $"&sig={System.Net.WebUtility.UrlEncode(signature)}";
    }
    catch (Exception ex)
    {
        context.Trace("User delegation SAS generation failed: " + ex.Message);
        return "";
    }
}" />
